starterCss:
/* Build a mountain scene using pure CSS:
   - Sky: gradient from dark blue to light blue
   - Sun: yellow circle with a glow effect
   - Mountains: triangles using clip-path, different shades
   - Ground: green gradient for grass
   Scene should be 500x300px */
.scene {
  width: 500px;
  height: 300px;
  position: relative;
  overflow: hidden;
  border-radius: 12px;
}

referenceSolutions:
.scene {
  width: 500px;
  height: 300px;
  position: relative;
  overflow: hidden;
  border-radius: 12px;
}
.sky {
  position: absolute;
  inset: 0;
  background: linear-gradient(to bottom, rgb(25, 25, 112), rgb(135, 206, 235));
}
.sun {
  position: absolute;
  width: 60px;
  height: 60px;
  background-color: rgb(255, 215, 0);
  border-radius: 50%;
  top: 40px;
  right: 80px;
  box-shadow: 0 0 40px 20px rgba(255, 215, 0, 0.4);
}
.mountain {
  position: absolute;
  bottom: 0;
  width: 100%;
}
.mountain-back {
  height: 200px;
  background-color: rgb(75, 85, 100);
  clip-path: polygon(0% 100%, 25% 20%, 50% 70%, 75% 10%, 100% 100%);
}
.mountain-front {
  height: 160px;
  background-color: rgb(60, 70, 85);
  clip-path: polygon(0% 100%, 15% 40%, 40% 80%, 60% 30%, 85% 70%, 100% 100%);
}
.ground {
  position: absolute;
  bottom: 0;
  width: 100%;
  height: 60px;
  background: linear-gradient(to bottom, rgb(76, 153, 0), rgb(34, 102, 0));
}

